#include <stdio.h>
#include <limits.h>
#define MAX_N 1001
const long long NEG_INF = -250000000;
bool isInBounds(int x, int y, int n) {
    return x >= 1 && x <= n && y >= 1 && y <= n;
}
long long dp(int i, int j, int n, long long memo[MAX_N + 1][MAX_N + 1], long long A[MAX_N + 1][MAX_N + 1]) {
    if (!isInBounds(i, j, n)) return INT_MIN;
    if (memo[i][j] != LLONG_MIN) return memo[i][j];
    if (i == n && j == n) return A[i][j];
    memo[i][j] = A[i][j] + (dp(i + 1, j, n, memo, A) > dp(i, j + 1, n, memo, A) ? dp(i + 1, j, n, memo, A) : dp(i, j + 1, n, memo, A));
    return memo[i][j];
}
int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    long long V[MAX_N + 1][MAX_N + 1] = {0};
    long long A[MAX_N + 1][MAX_N + 1];
    long long memo[MAX_N + 1][MAX_N + 1];
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= n; j++) {
            A[i][j] = NEG_INF;
            memo[i][j] = LLONG_MIN;
        }
    }
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            scanf("%lld", &V[i][j]);
        }
    }
    while (m--) {
        int x, y, z;
        scanf("%d %d %d", &x, &y, &z);
        for (int i = x - z; i <= x + z; i++) {
            if (i <= x) {
                for (int j = y - (i - x + z); j <= y + (i - x + z); j++) {
                    if (isInBounds(i, j, n)) {
                        A[i][j] = V[i][j];
                    }
                }
            } else {
                for (int j = y - (x - i + z); j <= y + (x - i + z); j++) {
                    if (isInBounds(i, j, n)) {
                        A[i][j] = V[i][j];
                    }
                }
            }
        }
    }
    long long maxSum = dp(1, 1, n, memo, A);
    if (maxSum < NEG_INF) {
        printf("NO\n");
    } else {
        printf("YES\n");
        printf("%lld\n", maxSum);
    }
    return 0;
}

