import java.util.*;
import java.lang.*;
import java.io.*;
public class Main {
    private static final long NEG_INF = -250000000;
    private static boolean isInBounds(int x, int y, int n) {
        return x >= 1 && x <= n && y >= 1 && y <= n;
    }
    private static long dp(int i, int j, int n, long[][] memo, long[][] A) {
        if (!isInBounds(i, j, n)) return Long.MIN_VALUE;
        if (memo[i][j] != Long.MIN_VALUE) return memo[i][j];
        if (i == n && j == n) return A[i][j];
        memo[i][j] = A[i][j] + Math.max(dp(i + 1, j, n, memo, A), dp(i, j + 1, n, memo, A));
        return memo[i][j];
    }
    public static void main(String[] args) throws java.lang.Exception {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int m = scanner.nextInt();
        long[][] V = new long[n + 1][n + 1];
        long[][] A = new long[n + 1][n + 1];
        long[][] memo = new long[n + 1][n + 1];
        for (int i = 0; i <= n; i++) {
            Arrays.fill(memo[i], Long.MIN_VALUE);
        }
        for (int i = 0; i <= n; i++) {
            Arrays.fill(A[i], NEG_INF);
        }
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                V[i][j] = scanner.nextLong();
            }
        }
        while (m-- > 0) {
            int x = scanner.nextInt();
            int y = scanner.nextInt();
            int z = scanner.nextInt();
            for (int i = x - z; i <= x + z; i++) {
                if (i <= x) {
                    for (int j = y - (i - x + z); j <= y + (i - x + z); j++) {
                        if (isInBounds(i, j, n)) {
                            A[i][j] = V[i][j];
                        }
                    }
                } else {
                    for (int j = y - (x - i + z); j <= y + (x - i + z); j++) {
                        if (isInBounds(i, j, n)) {
                            A[i][j] = V[i][j];
                        }
                    }
                }
            }
        }
        long maxSum = dp(1, 1, n, memo, A);
        if (maxSum < NEG_INF) {
            System.out.println("NO");
        } else {
            System.out.println("YES");
            System.out.println(maxSum);
        }
        scanner.close();
    }
}

