    if not is_in_bounds(i, j, n):
        return float('-inf')
    if memo[i][j] != float('-inf'):
        return memo[i][j]
    if i == n and j == n:
        return A[i][j]
    memo[i][j] = A[i][j] + max(dp(i + 1, j, n, memo, A), dp(i, j + 1, n, memo, A))
    return memo[i][j]

