const NEG_INF = -250000000;
function isInBounds(x, y, n) {
    return x >= 1 && x <= n && y >= 1 && y <= n;
}
function dp(i, j, n, memo, A) {
    if (!isInBounds(i, j, n)) return -Infinity;
    if (memo[i][j] !== -Infinity) return memo[i][j];
    if (i === n && j === n) return A[i][j];
    memo[i][j] = A[i][j] + Math.max(dp(i + 1, j, n, memo, A), dp(i, j + 1, n, memo, A));
    return memo[i][j];
}
function main() {
    const [n, m] = input[idx++].split(' ').map(Number);
    const V = Array.from({ length: n + 1 }, () => Array(n + 1).fill(0));
    const A = Array.from({ length: n + 1 }, () => Array(n + 1).fill(NEG_INF));
